sql:
SELECT session_id, AVG(average_speed) AS avg_speed
FROM car_performance
GROUP BY session_id;

external_knowledge:
; Average speed is a key factor in determining a car's performance; 
; Top speed is a critical metric for evaluating a car's potential; 
; Fuel consumption and tire degradation are essential factors in understanding a car's efficiency and maintenance needs; 
; Weather conditions significantly impact car performance and driver behavior; 
; Driver performance is evaluated based on points scored, penalties received, overtakes, and the number of times they were overtaken.

sql:
SELECT session_id, lap_time, average_speed
FROM car_performance
WHERE lap_time < 95.0;

